y_2: 'Raw provider states never become final front-end status copy without platform mapping.', conversation_list: 'Collaboration conversations', conversation_list_desc: 'Chat is used for assistance and explanation. It does not constitute trade authorization, approval decision, or execution fact.', trader_chat_title: 'Trading collaboration chat', trader_chat_desc: 'Controlled support channel for traders, support agents, and clients.', formal_flow_required: 'Formal workflow remains mandatory', formal_flow_required_body: 'Chat does not create trade authorization, and it does not replace withdrawal approval or on-chain completion facts.', chat_sample_1: 'Is there still enough depth behind this quote?', chat_sample_2: 'Depth is currently available, but you still need to complete formal authorization with your PIN.', chat_placeholder: 'Type a message to trader / support', send: 'Send', team_access_desc: 'Institution admins manage members, roles, and account scope.', invite_member: 'Invite member', member_email: 'Member email', role_placeholder: 'Role: admin / operator / approver', account_scope: 'Account scope', send_invitation: 'Send invitation', modal_submitWithdrawal_title: 'Confirm withdrawal request submission', modal_submitWithdrawal_body: 'This action creates a new withdrawal request object and places it into approval-pending state.', modal_approveWithdrawal_title: 'Confirm withdrawal approval', modal_approveWithdrawal_body: 'Approving the request moves it into the next execution stage and may later lead to broadcast and on-chain tracking.', modal_approveAddress_title: 'Confirm destination approval', modal_approveAddress_body: 'Approving the destination makes it selectable for withdrawals within the current account scope.', modal_confirmTrade_title: 'Confirm trade authorization', modal_confirmTrade_body: 'This action creates a formal trade authorization record bound to quote, session, device, and actor context.', toast_submitWithdrawal: 'Withdrawal request submitted', toast_approveWithdrawal: 'Withdrawal request approved', toast_approveAddress: 'Destination approved', toast_confirmTrade: 'Trade authorization confirmed',
